var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"헤헤, 맛있는 햄버거 냄새가 나서 와봤더니 익숙한 얼굴이 있잖아?","JPN":" へへ、おいしいハンバーガーの匂いがして出てみたら、見慣れた顔がいるじゃん！","ENG":" Hehe, I followed the smell of delicious hamburgers and found a familiar face here.","TWN":"嘿嘿，我是聞到漢堡香而來的，結果你也在？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그럼 잘 먹을게? 아앙~","JPN":" それじゃあ、いっただきまーす。あ～む。","ENG":" Ooh, this is going to be good! AAAAH!","TWN":"那我要開動囉，啊～～"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"...응? 종신계약? 그거 하면 매주 이런 걸 주겠다고?","JPN":" ……え？　終身契約？　それやれば、毎週こんなのくれるって？","ENG":" Hmm? A lifetime contract? If I do that, I can have a burger every week?","TWN":"…嗯？終身契約？只要簽名就每天給我吃漢堡？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"흐흥~ 사장님 말이야, 고작 그런 조건으로 그림자와 손을 잡을 생각을 하다니 겁이 없구나? 내가 인간에게 호의적인 편이라는 걸 다행으로 알라구.","JPN":" ふふ～ん。社長さあ、そんなちっぽけな条件でシャドウと手を組むつもりだったなんて、大胆だね？　私が人間に好意的なのを幸運と思えよ。","ENG":" H-hmm... Hey Boss, do you really think you can partner with a Shadow that easily? Just know how lucky you are that I'm kind enough to humans.","TWN":"呵呵～我說老闆，你竟然想用這種條件和暗影合作，還真是大膽，你真的要慶幸我對人類沒有惡意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…….","JPN":" ……","ENG":" ...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이거 비밀로 해주는 건 확실한 거지? 그런 계약을 셰나가 알게 됐다간 우리 둘 다 큰일이야. 특히 내 목숨이 위험하다구.","JPN":" これ、確実に内緒にしてくれるんだよね？　そんな契約をシェナが知ったら、二人とも大変なことになるんだ。特に私の命が危ない。","ENG":" This is just between you and me, right? If Shena finds out about this, then we'll both be in big trouble! But especially me...","TWN":"你會幫我保密吼？要是被世娜知道我們二個都會有麻煩的，我很可能會小命不保。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으음… 역시 거절하는 게 좋겠어. 햄버거를 좋아하긴 하지만 그것 때문에 죽고 싶진 않아.","JPN":" ううん……やっぱり断った方がイイと思う。ハンバーガーは好きだけど、そのために死にたくないもん。","ENG":" Mmm... I think it's best if I don't. I mean, I like hamburgers, but not enough to die for them.","TWN":"嗯…還是拒絕吧？我是很愛吃漢堡啦，但還沒愛到連命都不要。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"에…? 감자튀김이랑 콜라까지? 그것도 매일매일?","JPN":" えっ……？　フライドポテトにコーラまで？　それも毎日？","ENG":" Huh...? You're gonna give me fries and a drink too?! And every day at that?!","TWN":"什麼…？再加碼薯條和可樂？而且是每天供應？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으으으…….","JPN":" ううぅ……","ENG":" Ngh...","TWN":"呃呃呃……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"에라, 모르겠다! 이거 걸리면 무조건 사장님 탓이라고 할 거야! 알아들어?!","JPN":" まあ、いいっか！　これバレたら全部社長のせいにしちゃうから！　わかった！？","ENG":" Agh, I dunno anymore! If I get caught, I'm telling her that it was all your idea, got that?!","TWN":"算啦！不管啦！要是被抓到的話，我會說都是老闆的錯喔！知道嗎？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};